user.age = 26;         // This is allowed
user.email = "a@b.c"; // Adding properties is allowed
console.log(user);

// user = {}; // TypeError: Assignment to constant variable

const colors = ["red", "green"];
colors.push("blue");   // Modifying array contents is allowed
