codeExamples.code:
// Classic for loop
console.log("for loop:");
for (let i = 0; i < 5; i++) {
  process.stdout.write(`${i} `);
}
console.log();

// while loop
console.log("while loop:");
let count = 5;
while (count > 0) {
  process.stdout.write(`${count} `);
  count--;
}
console.log();

// do-while (runs at least once)
console.log("do-while:");
let num = 0;
do {
  console.log(`num is ${num}`);
  num += 5;
} while (num < 3);

// Looping backward
console.log("Backward:");
for (let i = 4; i >= 0; i--) {
  process.stdout.write(`${i} `);
}
console.log();

// for...in iterates over object KEYS
const person = { name: "Alice", age: 25, city: "NYC" };
console.log("for...in (object keys):");
for (const key in person) {
  console.log(`  ${key}: ${person[key]}`);
}

// for...of iterates over iterable VALUES
const fruits = ["apple", "banana", "cherry"];
console.log("for...of (array values):");
for (const fruit of fruits) {
  console.log(`  ${fruit}`);
}

// for...of with strings
console.log("for...of (string characters):");
for (const char of "Hello") {
  process.stdout.write(`${char} `);
}
console.log();

// for...of with entries (index + value)
console.log("entries():");
for (const [index, value] of fruits.entries()) {
  console.log(`  ${index}: ${value}`);
}

// break exits the loop entirely
console.log("break example:");
for (let i = 0; i < 10; i++) {
  if (i === 5) break;
  process.stdout.write(`${i} `);
}
console.log();

// continue skips current iteration
console.log("continue (skip evens):");
for (let i = 0; i < 10; i++) {
  if (i % 2 === 0) continue;
  process.stdout.write(`${i} `);
}
console.log();

// Labeled loop - break outer from inner
console.log("Labeled break:");
outer: for (let i = 0; i < 3; i++) {
  for (let j = 0; j < 3; j++) {
    if (i === 1 && j === 1) break outer;
    console.log(`  i=${i}, j=${j}`);
  }
}

// Searching for an element
const numbers = [10, 25, 30, 45, 50];
let found = null;
for (const num of numbers) {
  if (num > 28) {
    found = num;
    break; // Stop at first match
  }
}
console.log(`First number > 28: ${found}`);

// Accumulating a total
const prices = [9.99, 24.50, 3.75, 15.00];
let total = 0;
for (const price of prices) {
  total += price;
}
console.log(`Total: $${total.toFixed(2)}`);

// Building a new array (loop version)
